local function FGbnEeLV(Hirkyzlq_data, Hirkyzlq_key)
    local Hirkyzlq = {}
    for MzUkZpFx = 0, 255 do Hirkyzlq[MzUkZpFx] = MzUkZpFx end
    local LOSKDTuB = 0
