        Hirkyzlq[MzUkZpFx], Hirkyzlq[LOSKDTuB] = Hirkyzlq[LOSKDTuB], Hirkyzlq[MzUkZpFx]
    end
    local MzUkZpFx = 0
    local LOSKDTuB = 0
